'use strict';

exports.operation = function operation(options = {}) {
  const maxRetries = Number(options.retries ?? 0);
  let attempts = 0;
  let mainError = null;

  return {
    attempt(fn) {
      attempts += 1;
      fn(attempts);
    },
    retry(error) {
      if (!error) return false;
      mainError = mainError ?? error;
      if (attempts > maxRetries) return false;
      return true;
    },
    mainError() {
      return mainError;
    },
  };
};
